style.t:
@media (min-width: 768px) {
    /* Frosted Aurora Navbar - High-End Static Design (Desktop Only) */
    .o_main_navbar {
        position: sticky !important;
        top: 0 !important;
        height: 50px !important;
        /* Multi-stop gradient for a more "expensive" look */
        background: linear-gradient(135deg, rgba(255, 255, 255, 0.95) 0%, rgba(255, 255, 255, 0.85) 100%) !important;
        border-top: 1px solid rgba(255, 255, 255, 0.6) !important; /* Line of Light */
        border-bottom: 2px solid  !important;
        display: flex !important;
        align-items: center !important;
        padding: 0 20px !important;
        z-index: 2000 !important;
        box-shadow: 0 4px 30px rgba(0, 0, 0, 0.05) !important;
        overflow: visible !important;
        transition: none !important;
    }

    /* Regular glass effect for the navbar (Static) */
    .o_main_navbar::before {
        content: "" !important;
        position: absolute !important;
        top: 0 !important; left: 0 !important; right: 0 !important; bottom: 0 !important;
        backdrop-filter: blur(25px) saturate(200%) !important;
        -webkit-backdrop-filter: blur(25px) saturate(200%) !important;
        z-index: -1 !important;
        pointer-events: none !important;
    }

    /* Home Menu Upgrade: Aurora Mesh Gradient & Independent Stability */
    .o_navbar_apps_menu .dropdown-menu.show {
        position: fixed !important;
        top: 0 !important;
        left: 0 !important;
        width: 100vw !important;
        height: 100vh !important;
        min-width: 100vw !important;
        min-height: 100vh !important;
        z-index: 3000 !important;
        /* Aurora Mesh Gradient Effect */
        background: radial-gradient(circle at 10% 10%, 15 0%, transparent 50%),
                    radial-gradient(circle at 90% 10%, #4facfe15 0%, transparent 50%),
                    radial-gradient(circle at 50% 90%, 10 0%, transparent 50%),
                    rgba(255, 255, 255, 0.45) !important;
        backdrop-filter: blur(40px) saturate(220%) !important;
        -webkit-backdrop-filter: blur(40px) saturate(220%) !important;
        transform: none !important;
        transition: none !important;
        display: block !important;
    }

    /* Force Odoo's control panel and action manager to stay behind */
    .o_action_manager, .o_control_panel {
        z-index: 10 !important;
        position: relative !important;
    }

    /* Vibrant Typography and Interactive Links - Refined */
    .o_main_navbar .o_menu_brand, 
    .o_main_navbar .o_nav_entry,
    .o_main_navbar .o_menu_sections .dropdown-toggle,
    .o_main_navbar .o_menu_systray .dropdown-toggle,
    .o_main_navbar .o_menu_systray .o_nav_entry {
        color: #1a2a3a !important;
        font-weight: 700 !important;
        font-size: 14px !important;
        letter-spacing: -0.01em !important;
        height: 50px !important;
        line-height: 50px !important;
        padding: 0 15px !important;
        background: transparent !important;
        border: none !important;
        display: flex !important;
        align-items: center !important;
        transition: none !important;
    }

    /* Hover Effect: Soft Glow (Static) */
    .o_main_navbar .o_menu_brand:hover,
    .o_main_navbar .o_nav_entry:hover,
    .o_main_navbar .o_menu_sections .dropdown-toggle:hover {
        color:  !important;
        background: rgba(255, 255, 255, 0.4) !important;
        box-shadow: inset 0 0 10px rgba(255, 255, 255, 0.5) !important;
    }

    /* Active State: Defined Glow Underline */
    .o_main_navbar .show > .dropdown-toggle {
        background: rgba(255, 255, 255, 0.5) !important;
        color:  !important;
        box-shadow: inset 0 -3px 0 , 0 5px 15px 20 !important;
    }

    /* Premium Dropdowns - Glass & Clean */
    .o_main_navbar .dropdown-menu {
        border: 1px solid rgba(255, 255, 255, 0.4) !important;
        border-radius: 0 0 16px 16px !important;
        box-shadow: 0 20px 40px rgba(0, 0, 0, 0.1) !important;
        background: rgba(255, 255, 255, 0.9) !important;
        backdrop-filter: blur(20px) !important;
        padding: 10px !important;
        margin-top: 0 !important;
        z-index: 2100 !important;
        transition: none !important;
        animation: none !important;
    }

    .o_main_navbar .dropdown-menu .dropdown-item {
        border-radius: 10px !important;
        padding: 10px 18px !important;
        font-weight: 600 !important;
        color: #2c3e50 !important;
        transition: none !important;
    }

    .o_main_navbar .dropdown-menu .dropdown-item:hover {
        background:  !important;
        color: #ffffff !important;
    }

    /* App Menu Icon - Circular Purple Button Fix */
    .o_main_navbar .o_navbar_apps_menu {
        margin-right: 15px !important;
    }

    .o_main_navbar .o_navbar_apps_menu .dropdown-toggle {
        width: 36px !important;
        height: 36px !important;
        background: #5D50A2 !important; /* Requested Purple */
        color: #ffffff !important;
        border-radius: 50% !important;
        display: flex !important;
        align-items: center !important;
        justify-content: center !important;
        box-shadow: 0 4px 15px rgba(93, 80, 162, 0.3) !important;
        padding: 0 !important;
        font-size: 18px !important;
        transition: none !important;
    }

    .o_main_navbar .o_navbar_apps_menu .dropdown-toggle:hover {
        background: #6D60B2 !important;
        color: #ffffff !important;
        transform: none !important;
    }
}

/* Stable Minimalist Navbar - Accessible and Professional */
@media (min-width: 768px) {
    .o_main_navbar {
        position: sticky !important;
        top: 0 !important;
        z-index: 2000 !important;
        opacity: 0.8 !important; /* Subtle when not in use */
        transition: none !important;
    }

    .o_main_navbar:hover, 
    .o_main_navbar:focus-within,
    .o_main_navbar:has(.show) {
        opacity: 1 !important;
        background: rgba(255, 255, 255, 0.95) !important;
    }
}

/* High-End Fullscreen Menu - Professional and Modern */
/* Full-screen Background Container */
/* Full-screen Background Container */
/* Brute-force Full-screen for the whole container */
.o_navbar_apps_menu .dropdown-menu.show {
    position: fixed !important;
    top: 0 !important;
    left: 0 !important;
    right: 0 !important;
    bottom: 0 !important;
    width: 100vw !important;
    height: 100vh !important;
    min-width: 100vw !important;
    min-height: 100vh !important;
    margin: 0 !important;
    padding: 0 !important;
    border: none !important;
    background: transparent !important; 
    z-index: 9999 !important;
    display: block !important;
}

.o_navbar_apps_menu .dropdown-menu-custom {
    display: grid !important;
    justify-content: center !important;
    align-content: flex-start !important;
    width: 100% !important;
    height: 100% !important;
    /* "Clear Water" Effect: Subtle blue tint, high saturation */
    background: radial-gradient(circle at top left, rgba(220, 240, 255, 0.1) 0%, rgba(255, 255, 255, 0) 100%) !important;
    backdrop-filter: blur(20px) saturate(200%) !important;
    -webkit-backdrop-filter: blur(20px) saturate(200%) !important;
    padding: 100px 20px 50px !important;
    overflow-y: auto !important;
    gap: 10px 0 !important;
    transition: none !important;
    animation: none !important;
}

/* Desktop Specific: 5 Grid Layout for better spacing */
@media (min-width: 768px) {
    .o_navbar_apps_menu .dropdown-menu-custom {
        grid-template-columns: repeat(5, 120px) !important; /* 5 columns of 120px = 600px total */
    }

    .o_navbar_apps_menu .dropdown-menu-custom .search-container {
        grid-column: span 5 !important;
        width: 600px !important;
    }

    .o_navbar_apps_menu .dropdown-menu-custom .o_app {
        width: 110px !important;
        height: 130px !important;
        margin: 5px !important;
        /* Glass Card Effect */
        background: rgba(255, 255, 255, 0.15) !important;
        border: 1px solid rgba(255, 255, 255, 0.3) !important;
        border-radius: 18px !important;
        box-shadow: 0 10px 30px rgba(0, 0, 0, 0.05) !important;
        backdrop-filter: blur(10px) !important;
        display: flex !important;
        flex-direction: column !important;
        align-items: center !important;
        justify-content: center !important;
        color: #1a2a3a !important;
        font-weight: 600 !important;
    }

    .o_navbar_apps_menu .dropdown-menu-custom .o_app:hover {
        background: rgba(255, 255, 255, 0.3) !important;
        border-color: rgba(255, 255, 255, 0.6) !important;
        box-shadow: 0 15px 40px rgba(0, 0, 0, 0.1) !important;
    }
}

@keyframes slideDownBounce {
    0% { transform: translateY(-100%); opacity: 0; }
    70% { transform: translateY(0); opacity: 1; }
    85% { transform: translateY(-15px); }
    100% { transform: translateY(0); }
}

/* Search Bar Base Styling */
.o_navbar_apps_menu .dropdown-menu-custom .search-container {
    justify-self: center !important;
    margin-bottom: 30px !important;
    display: flex !important;
    flex-direction: column !important;
    align-items: center !important;
}

/* Base App Items Styling */
.o_navbar_apps_menu .dropdown-menu .dropdown-item,
.o_navbar_apps_menu .dropdown-menu-custom .dropdown-item,
.o_navbar_apps_menu .dropdown-menu-custom .o_app {
    display: flex !important;
    flex-direction: column !important;
    align-items: center !important;
    justify-content: center !important;
    background: rgba(255, 255, 255, 0.15) !important;
    border-radius: 16px !important;
    transition: all 0.5s cubic-bezier(0.23, 1, 0.32, 1) !important;
    border: 1px solid rgba(255, 255, 255, 0.4) !important;
    backdrop-filter: blur(10px) !important;
    box-shadow: 0 4px 15px rgba(0,0,0,0.05) !important;
    animation: itemFadeIn 0.6s ease-out backwards !important;
}

@keyframes itemFadeIn {
    from { opacity: 0; transform: translateY(30px); }
    to { opacity: 1; transform: translateY(0); }
}

/* Interactive Hover States */
.o_navbar_apps_menu .dropdown-menu .dropdown-item:hover,
.o_navbar_apps_menu .dropdown-menu-custom .o_app:hover {
    background: rgba(255, 255, 255, 0.3) !important;
    transform: translateY(-8px) scale(1.06) !important;
    box-shadow: 0 15px 30px rgba(0,0,0,0.1) !important;
    border-color: rgba(255, 255, 255, 0.8) !important;
}

.o_navbar_apps_menu .dropdown-menu .dropdown-item img,
.o_navbar_apps_menu .dropdown-menu-custom .o_app img,
.o_navbar_apps_menu .dropdown-menu-custom .o-app-icon {
    width: 48px !important; /* Smaller icons for 6-grid */
    height: 48px !important;
    max-width: 48px !important;
    margin-bottom: 8px !important;
    filter: drop-shadow(0 10px 15px rgba(0,0,0,0.15)) !important;
    transition: all 0.5s ease !important;
}

.o_navbar_apps_menu .dropdown-menu .dropdown-item span,
.o_navbar_apps_menu .dropdown-menu-custom .o_app div,
.o_navbar_apps_menu .dropdown-menu-custom .o_app span {
    font-size: 11px !important; /* Smaller font for 6-grid */
    font-weight: 600 !important;
    color: #111 !important;
    text-align: center !important;
    line-height: 1.2 !important;
    text-shadow: 0 1px 1px rgba(255,255,255,0.5) !important;
}

/* Modern Search Bar - Water Style */
.o_navbar_apps_menu .dropdown-menu-custom .search-container {
    flex: 0 0 100% !important;
    display: flex !important;
    flex-direction: column !important;
    align-items: center !important;
    justify-content: flex-start !important;
    order: -1 !important;
    margin: 0 0 30px 0 !important;
    padding: 0 !important;
    animation: itemFadeIn 0.8s ease-out 0.1s backwards !important;
    z-index: 2600 !important;
}

.o_navbar_apps_menu .dropdown-menu-custom .search-input {
    width: 100% !important;
    max-width: 600px !important; /* Back to original width */
    background: rgba(255, 255, 255, 0.25) !important;
    border: 1px solid rgba(255, 255, 255, 0.5) !important;
    border-radius: 20px !important;
    padding: 12px 24px !important;
    box-shadow: 0 10px 30px rgba(0,0,0,0.05) !important;
    transition: all 0.3s ease !important;
    display: center !important;
    align-items: center !important;
    backdrop-filter: blur(10px) !important;
}

.o_navbar_apps_menu .dropdown-menu-custom .search-results {
    width: 100% !important;
    max-width: 600px !important;
    background: rgba(255, 255, 255, 0.4) !important;
    border-radius: 0 0 20px 20px !important;
    margin-top: -10px !important;
    padding: 20px !important;
    box-shadow: 0 20px 40px rgba(0,0,0,0.1) !important;
    max-height: 50vh !important;
    overflow-y: auto !important;
    border: 1px solid rgba(255, 255, 255, 0.5) !important;
    border-top: none !important;
    z-index: 2601 !important;
    backdrop-filter: blur(20px) !important;
}

.o_navbar_apps_menu .dropdown-menu-custom .search-result {
    display: flex !important;
    align-items: center !important;
    padding: 12px 20px !important;
    color: #111 !important;
    font-size: 16px !important;
    border-radius: 12px !important;
    transition: all 0.2s !important;
    text-decoration: none !important;
    margin-bottom: 5px !important;
    background-color: transparent !important;
}

.o_navbar_apps_menu .dropdown-menu-custom .search-result:hover,
.o_navbar_apps_menu .dropdown-menu-custom .search-result.highlight {
    background-color: rgba(255,255,255,0.4) !important;
    color:  !important;
    padding-left: 30px !important;
}

.o_navbar_apps_menu .dropdown-menu-custom .search-input:focus-within {
    border-color: rgba(255, 255, 255, 0.8) !important;
    box-shadow: 0 15px 35px rgba(0,0,0,0.1) !important;
}

.o_navbar_apps_menu .dropdown-menu-custom .search-input .search-icon {
    color:  !important;
    font-size: 20px !important;
    margin-right: 15px !important;
}

.o_navbar_apps_menu .dropdown-menu-custom .search-input .form-control {
    color: #111 !important;
    font-size: 18px !important;
    background: transparent !important;
    border: none !important;
    box-shadow: none !important;
}

/* Floating Close Button - Permanently Hidden */
.o_navbar_apps_menu .o_apps_menu_close {
    display: none !important;
}

/* Responsive Mobile View - 4 items per row */
@media (max-width: 767px) {
    .o_navbar_apps_menu .dropdown-menu.show,
    .o_navbar_apps_menu .dropdown-menu-custom {
        padding: 40px 10px 40px !important;
        grid-template-columns: repeat(4, 1fr) !important;
        gap: 10px !important;
    }

    .o_navbar_apps_menu .dropdown-menu-custom .search-container {
        grid-column: span 4 !important;
        width: 100% !important;
        margin-bottom: 25px !important;
    }

    .o_navbar_apps_menu .dropdown-menu .dropdown-item,
    .o_navbar_apps_menu .dropdown-menu-custom .dropdown-item,
    .o_navbar_apps_menu .dropdown-menu-custom .o_app {
        width: 100% !important; /* Grid cell handles the width */
        min-width: 75px !important;
        margin: 0 !important;
        padding: 15px 5px !important;
        min-height: 110px !important;
        border-radius: 16px !important;
    }

    .o_navbar_apps_menu .dropdown-menu .dropdown-item img,
    .o_navbar_apps_menu .dropdown-menu-custom .o_app img,
    .o_navbar_apps_menu .dropdown-menu-custom .o-app-icon {
        width: 42px !important;
        height: 42px !important;
        margin-bottom: 8px !important;
    }

    .o_navbar_apps_menu .dropdown-menu .dropdown-item span,
    .o_navbar_apps_menu .dropdown-menu-custom .o_app div,
    .o_navbar_apps_menu .dropdown-menu-custom .o_app span {
        font-size: 10px !important;
        line-height: 1.1 !important;
    }

    .o_navbar_apps_menu .o_apps_menu_close {
        top: 20px !important;
        left: 20px !important; 
        width: 40px !important;
        height: 40px !important;
    }

    .o_navbar_apps_menu .dropdown-menu-custom .search-input {
        padding: 10px 20px !important;
        max-width: 100% !important;
    }
}
